/**
 * API Service Tests
 *
 * Tests for the core API service functionality including:
 * - Token management
 * - Request headers
 * - Fetch with timeout
 * - Dashboard data fetching
 * - Attendance marking
 */

import api from '../api';
import * as SecureStore from 'expo-secure-store';

// Mock expo-secure-store
jest.mock('expo-secure-store', () => ({
  getItemAsync: jest.fn(),
  setItemAsync: jest.fn(),
  deleteItemAsync: jest.fn(),
}));

describe('APIService', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    (global.fetch as jest.Mock).mockClear();
  });

  describe('getToken', () => {
    it('should return null when no token is stored', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue(null);

      // Access private method via type assertion
      const token = await (api as any).getToken();

      expect(token).toBeNull();
      expect(SecureStore.getItemAsync).toHaveBeenCalledWith('user_token');
    });

    it('should return token when stored', async () => {
      const mockToken = 'test-token-123';
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue(mockToken);

      const token = await (api as any).getToken();

      expect(token).toBe(mockToken);
    });

    it('should clear corrupted token and return null', async () => {
      const decryptionError = new Error('Could not decrypt');
      (SecureStore.getItemAsync as jest.Mock).mockRejectedValue(decryptionError);
      (SecureStore.deleteItemAsync as jest.Mock).mockResolvedValue(undefined);

      const token = await (api as any).getToken();

      expect(token).toBeNull();
      expect(SecureStore.deleteItemAsync).toHaveBeenCalledWith('user_token');
    });
  });

  describe('getHeaders', () => {
    it('should return headers without token when not authenticated', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue(null);

      const headers = await (api as any).getHeaders();

      expect(headers).toEqual({
        'Content-Type': 'application/json',
      });
    });

    it('should return headers with Authorization token when authenticated', async () => {
      const mockToken = 'Bearer test-token-123';
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue(mockToken);

      const headers = await (api as any).getHeaders();

      expect(headers).toEqual({
        'Content-Type': 'application/json',
        Authorization: `Bearer ${mockToken}`,
      });
    });
  });

  describe('fetchWithTimeout', () => {
    it('should fetch data successfully within timeout', async () => {
      const mockResponse = { ok: true, json: async () => ({ data: 'test' }) };
      (global.fetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await (api as any).fetchWithTimeout('http://test.com', {});

      expect(result.ok).toBe(true);
      expect(global.fetch).toHaveBeenCalledWith(
        'http://test.com',
        expect.objectContaining({
          signal: expect.any(AbortSignal),
        })
      );
    });

    it('should abort request when timeout is exceeded', async () => {
      (global.fetch as jest.Mock).mockImplementation(() =>
        new Promise((resolve) => setTimeout(resolve, 200))
      );

      await expect(
        (api as any).fetchWithTimeout('http://test.com', {}, 50)
      ).rejects.toThrow();
    });
  });

  describe('getDashboardData', () => {
    const mockTeacherId = 'teacher-123';
    const mockDashboardData = {
      teacher: {
        id: mockTeacherId,
        name: 'John Doe',
        code: 'T001',
        role: 'Teacher',
      },
      classTeacher: null,
      attendance: {
        date: '2024-01-15',
        status: null,
        inTime: null,
        outTime: null,
      },
      timetable: [],
      substitutions: [],
      gatePasses: [],
      appointments: [],
      unreadAnnouncements: 0,
    };

    it('should fetch dashboard data successfully', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => mockDashboardData,
      });

      const result = await api.getDashboardData(mockTeacherId);

      expect(result).toEqual(mockDashboardData);
      expect(global.fetch).toHaveBeenCalledWith(
        expect.stringContaining(`/mobile/teacher/${mockTeacherId}/dashboard`),
        expect.objectContaining({
          headers: expect.objectContaining({
            Authorization: 'Bearer test-token',
          }),
        })
      );
    });

    it('should throw error when fetch fails', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: false,
        status: 500,
      });

      await expect(api.getDashboardData(mockTeacherId)).rejects.toThrow(
        'Failed to fetch dashboard data'
      );
    });
  });

  describe('markTeacherAttendance', () => {
    const mockTeacherId = 'teacher-123';
    const mockAttendanceData = {
      status: 'present',
      inTime: '08:30',
    };

    it('should mark attendance successfully', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => ({ success: true }),
      });

