      expect(result).toEqual({ success: true });
      expect(global.fetch).toHaveBeenCalledWith(
        expect.stringContaining(`/mobile/teacher/${mockTeacherId}/attendance`),
        expect.objectContaining({
          method: 'POST',
          body: JSON.stringify(mockAttendanceData),
        })
      );
    });

    it('should throw error when marking fails', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: false,
      });

      await expect(
        api.markTeacherAttendance(mockTeacherId, mockAttendanceData)
      ).rejects.toThrow('Failed to mark attendance');
    });
  });

  describe('getTimetable', () => {
    const mockTeacherId = 'teacher-123';
    const mockTimetable = [
      {
        periodIndex: 1,
        classId: { name: 'Class A', section: '1' },
        subject: 'Math',
        room: '101',
      },
    ];

    it('should fetch timetable successfully', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => mockTimetable,
      });

      const result = await api.getTimetable(mockTeacherId);

      expect(result).toEqual(mockTimetable);
    });
  });

  describe('getClassStudents', () => {
    const mockTeacherId = 'teacher-123';
    const mockStudents = [
      { id: 's1', name: 'Student 1', rollNo: 1 },
      { id: 's2', name: 'Student 2', rollNo: 2 },
    ];

    it('should fetch class students successfully', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => mockStudents,
      });

      const result = await api.getClassStudents(mockTeacherId);

      expect(result).toEqual(mockStudents);
    });

    it('should throw error with custom message when provided', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: false,
        status: 403,
        json: async () => ({ error: 'Not authorized for this class' }),
      });

      await expect(api.getClassStudents(mockTeacherId)).rejects.toThrow(
        'Not authorized for this class'
      );
    });
  });

  describe('getPayslips', () => {
    const mockEmployeeId = 'emp-123';
    const mockPayslips = [
      { id: 'p1', month: 'January', year: 2024, netSalary: 50000 },
    ];

    it('should fetch payslips with default parameters', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => mockPayslips,
      });

      const result = await api.getPayslips(mockEmployeeId);

      expect(result).toEqual(mockPayslips);
      expect(global.fetch).toHaveBeenCalledWith(
        expect.stringContaining(`payslips/staff/${mockEmployeeId}?limit=24&skip=0`),
        expect.any(Object)
      );
    });

    it('should fetch payslips with year filter', async () => {
      (SecureStore.getItemAsync as jest.Mock).mockResolvedValue('test-token');
      (global.fetch as jest.Mock).mockResolvedValue({
        ok: true,
        json: async () => mockPayslips,
      });

      await api.getPayslips(mockEmployeeId, 2024);

      expect(global.fetch).toHaveBeenCalledWith(
        expect.stringContaining('year=2024'),
        expect.any(Object)
      );
    });
  });
});

